return context.decrypt("1:ACP:eC3ohofZgcXJt92oV0Nv/a/4cLPVeiYyReOgcOLCRAw=");


Iterator iterator = null;
BufferedWriter writer = null;
List roleDivisions = null;

try {

  //String inputData = (String)config.get("roleDivision");      
  String inputData = "Low,Medium,High";   
  log.error("inputData :" +inputData);
  roleDivisions = new ArrayList();

  if (!Util.isNullOrEmpty(inputData)) {
    if (inputData.contains(",")) {
      roleDivisions = Arrays.asList(inputData.split(","));
    } else {
      roleDivisions.add(inputData);
    }
  }
  log.debug("roleDivisions :" +roleDivisions);

  //SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd_HH-mm-ss");
  String fileName = "icamInstitutionalRoleMembershipReport1045" +".csv";
  // File file = new File("//Data//sailpoint//datafiles//MissingRoleTargets//" + fileName);
  File file = new File("D:/csv files/Test/" + fileName);



  QueryOptions options = new QueryOptions();


  String hql =
    "sql:select " +
    "i.name as identity_name, " +
    "i.firstname as first_name, " +
    "i.lastname as last_name, " +
    "i.department as department, " +
    "b.name as role_name, " +
    "ie.name as role_type, " +
    "b.owner as role_owner " +
    "from spt_identity_entitlement ie " +
    "join spt_bundle b on ie.value = b.name " +
    "join spt_identity i on ie.identity_id = i.id " +
    "and ie.value is not null " +
    "and upper(b.role_criticality) in ('" + inputData.toUpperCase().replace(",", "','") + "') " +
    "order by i.name";


  // "where ie.name in ('detectedRoles','assignedRoles') " +

  iterator = context.search(hql, null, options);
  log.error("hql : " + hql);

  writer = new BufferedWriter(new FileWriter(file));
  writer.write("IdentityName,FirstName,LastName,Department,RoleName,RoleType,RoleOwner,RoleDescription,RoleDivision,RoleLogicalAppName");
  writer.newLine();

  String identityName = "";
  String firstName = "";
  String lastName = "";
  String department = "";
  String roleName = "";
  String roleType = "";
  String roleOwner = "";
  String roleDescription = "";
  String roleDivision = "";
  String roleLogicalAppName = "";


  while (iterator.hasNext()) {

    Object[] row = (Object[]) iterator.next();
    roleDescription = "";
    roleDivision = "";
    roleLogicalAppName = "";

    identityName = (Util.otos(row[0]) != null ? Util.otos(row[0]) : "").replace("\r", " ").replace("\n", " ");
    firstName = (Util.otos(row[1])!= null?Util.otos(row[1]):"").replace("\r", " ").replace("\n", " ");
    lastName = (Util.otos(row[2])!=null?Util.otos(row[2]):"").replace("\r", " ").replace("\n", " ");
    department = (Util.otos(row[3])!=null?Util.otos(row[3]):"").replace("\r", " ").replace("\n", " ");
    roleName = (Util.otos(row[4])!=null?Util.otos(row[4]):"").replace("\r", " ").replace("\n", " ");

    Bundle bundle = context.getObjectByName(Bundle.class, roleName);
    if (bundle != null) {
      roleDescription = bundle.getDescription("en_US");
      Map sysDescriptions = (Map) bundle.getAttribute("sysDescriptions");
      if (sysDescriptions != null) {
        roleDescription = Util.otos(sysDescriptions.get("en_US"))!=null?Util.otos(sysDescriptions.get("en_US")):"";
      }

      roleDivision =  (bundle.getAttribute("roleCriticality")!=null?bundle.getAttribute("roleCriticality"):"").replace("\r", " ").replace("\n", " ");       //role_criticality = RoleDivision   
      roleLogicalAppName = (bundle.getAttribute("roleLevel")!=null?bundle.getAttribute("roleLevel"):"").replace("\r", " ").replace("\n", " ");                      //role_level = appName
    }
    roleDescription = roleDescription != null?roleDescription.replace("\r", " ").replace("\n", " "):"";
    roleType = (Util.otos(row[5])!=null?Util.otos(row[5]):"").replace("\r", " ").replace("\n", " ");
    String roleOwnerId = Util.otos(row[6]);
    roleOwner = Util.isNotNullOrEmpty(roleOwnerId)?context.getObjectById(Identity.class,roleOwnerId).getName():"";

    String value = identityName.replace("\"","\"\"") + "," 
      + firstName.replace("\"","\"\"") + "," 
      + lastName.replace("\"","\"\"") + "," 
      + department.replace("\"","\"\"") + "," 
      + roleName.replace("\"","\"\"") + "," 
      + roleType.replace("\"","\"\"") + "," 
      + roleOwner.replace("\"","\"\"") + "," 
      + "\"" + (roleDescription != null ? roleDescription.replace("\"","\"\"") : "") + "\"," 
      + roleDivision.replace("\"","\"\"") + "," 
      + roleLogicalAppName.replace("\"","\"\"");

     log.error("DATA  : " + value);

    writer.write(value);
    writer.newLine();
  }
  writer.flush();
} catch (Exception e) {

  if(roleDivisions.isEmpty() || roleDivisions.size()<1) {
    throw new GeneralException("No roleDivision values found from Run Rule Task");
  }
  log.error("Exception in ReportsData1 : ", e);
} finally {
  Util.flushIterator(iterator);
  if (writer != null) {
    writer.close();
  }
}

return "Role Membership Report by RoleDivision";
















Iterator iterator = null;

try {

  Filter baseFilter = Filter.and(
    Filter.in("name", Arrays.asList("detectedRoles","assignedRoles")),
    Filter.notnull("value"),
    Filter.join("value", "Bundle.name")
  );

  QueryOptions options = new QueryOptions();
  options.addFilter(baseFilter);

  /* same structure kept */
  String properties = "identity , Bundle.name , name , Bundle.owner.name ";

  StringBuilder daatBuilder = new StringBuilder(8192);

  iterator = context.search(IdentityEntitlement.class, options, properties);

  log.error("ietrator : " + iterator);

  String identityName = "";
  String firstName = "";
  String lastName = "";
  String department = "";
  String roleName = "";
  String roleType = "";
  String roleOwner = "";
  String roleDescription = "";
  String roleDivision = "";
  String roleLogicalAppName = "";

  Identity identityObj = null;

  daatBuilder.append("IdentityName,FirstName,LastName,Department,RoleName,RoleType,RoleOwner,RoleDescription,RoleDivision,RoleLogicalAppName");

  while (iterator.hasNext()) {

    Object[] row = (Object[]) iterator.next();

    /* reset values each loop */
    identityName = "";
    firstName = "";
    lastName = "";
    department = "";

    identityObj = (Identity) row[0];

    if (identityObj != null) {
      identityName = Util.otos(identityObj.getName());
      firstName = Util.otos(identityObj.getFirstname());
      lastName = Util.otos(identityObj.getLastname());
      department = Util.otos(identityObj.getAttribute("department"));
    }

    roleName = Util.otos(row[1]);
    roleType = Util.otos(row[2]);
    roleOwner = Util.otos(row[3]);

    roleDescription = roleName;
    roleDivision = roleName;
    roleLogicalAppName = roleName;

    daatBuilder.append('\n')
      .append(identityName).append(',')
      .append(firstName).append(',')
      .append(lastName).append(',')
      .append(department).append(',')
      .append(roleName).append(',')
      .append(roleType).append(',')
      .append(roleOwner).append(',')
      .append(roleDescription).append(',')
      .append(roleDivision).append(',')
      .append(roleLogicalAppName);
  }

  log.error("Data ::: " + daatBuilder.toString());

} catch (Exception e) {

  log.error("Exception in ReportsData1 : ", e);

} finally {

  Util.flushIterator(iterator);
}

return "IIQ";


































